  const { t: tCustomFields } = useTranslation('customFields');
  let schema: Schema = isDonation
    ? makeSchema(cvvRequired, cardZipRequired, isEvent)
    : object().shape({});

  schema = schema.concat(
    object().shape({
      cardZip: string().when(
        ['type', 'eventTicketsAttributes', 'expressCheckoutMethod', 'totalPrice'],
        {
          is: (
            type: string,
            eventTicketsAttributes: Pick<ActionPageSubmission, 'eventTicketsAttributes'>[],
            expressCheckoutMethod: string,
            totalPrice: number
          ) => {
            // Don't require cardZip for free tickets
            if (isEvent && (eventTicketsAttributes?.length ?? 0) > 0 && totalPrice === 0) {
              return false;
            }

            return isEvent
              ? !expressCheckoutMethod && type === 'credit_card' && totalPrice > 0
              : !expressCheckoutMethod && type === 'credit_card';
