import { Flex } from '@chakra-ui/react';
import { FieldOptionsCustomFieldPositionsAttributes } from '@domain/actionPages';
import { ICustomField } from '@domain/customField';
import { PublicActionPage } from '@domain/publicActionPage';
import { LoadableCustomField } from '@pages/Finance/pages/Commitments/components/ViewCommitmentDrawer/components/CustomFieldsSection/components/LoadableCustomField';
import { CustomField } from '@ui/components/formControls/compositions/CustomField';
import { useCallback, useEffect, useMemo } from 'react';
import { useFormContext } from 'react-hook-form';
import {
  CUSTOM_FIELDS_BLOCK_ID,
  STANDARD_FIELDS_BLOCK_ID,
} from '../../../Designer/Form/Fields/components/constants';
import { getBlockFieldOrder } from '../../../Designer/Form/Fields/utils/getFieldOrder';
import { StandardFields } from './Fields/StandardFields/StandardFields';

export type ActionPageFormProps = {
  actionPage?: PublicActionPage;
  customFieldPositionAttributes?: FieldOptionsCustomFieldPositionsAttributes[];
  customFields?: ICustomField[];
};

export const ActionPageForm = ({
  actionPage,
  customFieldPositionAttributes,
  customFields,
}: ActionPageFormProps) => {
  const { trigger, watch } = useFormContext();
  const email = watch('email');
  const phone = watch('phone');
  const { fieldOrder: actionPageFieldOrder, requireEmailOrPhone } =
    actionPage?.fieldConfiguration || {};

  const getCustomField = useCallback(
    (id: string) => {
      return customFields?.find((field) => field.id === id);
    },
    [customFields]
  );

  const fieldOrder = useMemo(
    () => getBlockFieldOrder(actionPageFieldOrder),
    [actionPageFieldOrder]
  );

  const flexFlow = useMemo(
    () =>
      fieldOrder &&
      fieldOrder.length > 1 &&
      fieldOrder.indexOf(CUSTOM_FIELDS_BLOCK_ID) < fieldOrder.indexOf(STANDARD_FIELDS_BLOCK_ID)
        ? 'wrap-reverse'
        : undefined,
    [fieldOrder]
  );

  // Handle the dependent validation for `requireEmailOrPhone`
  useEffect(() => {
    if (requireEmailOrPhone && email) {
      trigger('phone');
    }
    if (requireEmailOrPhone && phone) {
      trigger('email');
    }
  }, [requireEmailOrPhone, email, trigger, phone]);

  return (
    <Flex flexDirection="column" flexFlow={flexFlow} gap={!flexFlow ? 2 : 4} width="full">
      <StandardFields actionPage={actionPage} />
      <Flex flexDirection="column" gap={4} justify="center" width="full">
        {customFieldPositionAttributes
          ?.sort((a, b) => a.position - b.position)
          .map((customFieldPositionAttribute) => {
            const field = getCustomField(customFieldPositionAttribute.customFieldId);

            return field ? (
              <CustomField
                customField={field}
                isLive
                isRequired={customFieldPositionAttribute.required}
                key={customFieldPositionAttribute.customFieldId}
                name={`customFieldResponsesAttributes.${customFieldPositionAttribute.customFieldId}`}
              />
            ) : (
              <LoadableCustomField
                customFieldId={customFieldPositionAttribute.customFieldId}
                isLive
                isRequired={customFieldPositionAttribute.required}
                key={customFieldPositionAttribute.customFieldId}
                name={`customFieldResponsesAttributes.${customFieldPositionAttribute.customFieldId}`}
              />
            );
          })}
      </Flex>
    </Flex>
  );
};

