import { Flex } from '@chakra-ui/react';
import { PublicActionPage } from '@domain/publicActionPage';
import { getStandardFieldOrder } from '@pages/ActionPages/pages/ActionPagesBuilder/Designer/Form/Fields/utils/getFieldOrder';
import { isDonationPage } from '@utils/isDonationPage/isDonationPage';
import { useMemo } from 'react';
import { AddressField } from './AddressField/AddressField';
import { EmailField } from './EmailField/EmailField';
import { EmploymentField } from './EmploymentField/EmploymentField';
import { MakeDonationAsSection } from './MakeDonationAsSection/MakeDonationAsSection';
import { NameField } from './NameField/NameField';
import { PhoneField } from './PhoneField/PhoneField';

type Props = {
  actionPage?: PublicActionPage;
};

export const StandardFields = ({ actionPage }: Props) => {
  const {
    displayAddress,
    displayEmail,
    displayEmployment,
    displayName,
    displayPhone,
    fieldOrder: actionPageFieldOrder,
    requireAddress,
    requireEmail,
    requireEmployment,
    requireName,
    requirePhone,
  } = actionPage?.fieldConfiguration || {};

  const fieldOrder = useMemo(
    () =>
      getStandardFieldOrder({
        displayAddress: displayAddress || requireAddress,
        displayEmail: displayEmail || requireEmail,
        displayEmployment: displayEmployment || requireEmployment,
        displayName: displayName || requireName,
        displayPhone: displayPhone || requirePhone,
        fieldOrder: actionPageFieldOrder,
        isDonation: isDonationPage(actionPage?.pageType),
      }),
    [
      displayAddress,
      requireAddress,
      displayEmail,
      requireEmail,
      displayEmployment,
      requireEmployment,
      displayName,
      requireName,
      displayPhone,
      requirePhone,
      actionPageFieldOrder,
      actionPage?.pageType,
    ]
  );

  return (
    <Flex alignItems="stretch" flexDirection="column" gap={4} justify="center" width="full">
      <MakeDonationAsSection
        actionPage={actionPage}
        displayOrganizationType={actionPage?.fieldConfiguration?.displayOrganizationType}
        includeOrganization={actionPage?.fieldConfiguration?.includeOrganization}
        requireOrganizationType={actionPage?.fieldConfiguration?.requireOrganizationType}
      />
      {fieldOrder.map((id) => {
        switch (id) {
          case 'email':
            return <EmailField actionPage={actionPage} key={id} />;
          case 'name':
            return <NameField actionPage={actionPage} key={id} />;
          case 'address':
            return <AddressField actionPage={actionPage} key={id} />;
          case 'phone':
            return <PhoneField actionPage={actionPage} key={id} />;
          case 'employment':
            return <EmploymentField actionPage={actionPage} key={id} />;
          default:
            return null;
        }
      })}
    </Flex>
  );
};

